script:
let locationSelected = false;
let map;
let marker;

frappe.ui.form.on("Employee", {
    refresh(frm){
        renderButton(frm)
    }
})


// render button
function renderButton(frm){

    const wrapper = frm.fields_dict.custom_location_picker.$wrapper

    wrapper.html(`
        <button class="btn btn-primary" id="pick_location_btn">
            Pick Location from Map
        </button>
    `)

    wrapper.find("#pick_location_btn").on("click", ()=>{
        openPopup(frm)
    })

}


// open dialog popup
function openPopup(frm){

    if(locationSelected){
        frappe.msgprint("Location already selected. Please refresh the page to select again.")
        return
    }

    const dialog = new frappe.ui.Dialog({
        title: "Select Location",
        fields:[{fieldtype:"HTML", fieldname:"map_html"}],
        size:"large"
    })

    dialog.show()

    setTimeout(()=>{
        loadMap(dialog, frm)
    },200)

}


// load leaflet map
function loadMap(dialog, frm){

    const wrapper = dialog.fields_dict.map_html.$wrapper

    wrapper.html(`
        <button class="btn btn-secondary" id="current_location_btn">
            📍 Use My Current Location
        </button>

        <div id="popup_map" style="height:400px;margin-top:10px;"></div>
    `)

    map = L.map("popup_map").setView([12.9716,77.5946],13)

    L.tileLayer(
        "https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",
        { attribution:"© OpenStreetMap"}
    ).addTo(map)

    map.on("click", (e)=>{
        setLocation(e.latlng, frm)
    })

    wrapper.find("#current_location_btn").on("click", ()=>{
        getCurrentLocation(frm)
    })

}


// set marker + update fields
function setLocation(latlng, frm){

    if(locationSelected){
        frappe.msgprint("Location already selected. Please refresh the page to select again.")
        return
    }

    marker = L.marker(latlng).addTo(map)

    frm.set_value("custom_site_latitude", latlng.lat)
    frm.set_value("custom_site_longitude", latlng.lng)

    locationSelected = true
}


// get current GPS location
function getCurrentLocation(frm){

    navigator.geolocation.getCurrentPosition((pos)=>{

        const lat = pos.coords.latitude
        const lng = pos.coords.longitude

        map.setView([lat,lng],18)

        setLocation({lat:lat, lng:lng}, frm)

    })
}
